import { cn } from '@/utils/cn';
import { cva, VariantProps } from 'class-variance-authority';
import { Component, mergeProps } from 'solid-js';
import type { BadgeProps } from './badge.types';
import { getColor } from '@/utils/helper';

const variants = cva('', {
  variants: {
    size: {
      '3xs': 'bad-3xs',
      '2xs': 'bad-2xs',
      xs: 'bad-xs',
      sm: 'bad-sm',
      md: 'bad-md',
      lg: 'bad-lg',
      xl: 'bad-xl',
      '2xl': 'bad-2xl',
      '3xl': 'bad-3xl',
    },
    variants: {
      outline: 'bad03',
      soft: 'bad02',
      dashed: 'bad04',
    },
  },
});
export type BadgeVariantsProps = VariantProps<typeof variants>;

export const Badge: Component<BadgeProps> = p => {
  p = mergeProps({ size: 'md', color: 'primary', content: 'lorem', variants: 'soft' } as const, p);

  return (
    <div
      class={cn(
        'bad00',
        variants({ size: p.size, variants: p.variants }),
        getColor(p.color),
        p.class?.root,
      )}
    >
      {typeof p.content === 'string' ? (
        <span class={cn('bad01', p.class?.child)}>{p.content}</span>
      ) : (
        <div class={p.class?.child}>{p.content as Element}</div>
      )}
    </div>
  );
};
